script:
frappe.ui.form.on("Check In", {
    refresh(frm) {
        toggle_new_item(frm);
    },

    override_item(frm) {
        toggle_new_item(frm);
    }
});

function toggle_new_item(frm) {
    if (frm.doc.override_item) {
        frm.set_df_property("new_item", "hidden", 0);
    } else {
        frm.set_df_property("new_item", "hidden", 1);
        frm.set_value("new_item", null);
    }
}

frappe.ui.form.on("Check In", {
    refresh(frm) {
        toggle_new_item(frm);
    },

    override_item(frm) {
        toggle_new_item(frm);
    },

    new_item(frm) {
        if (frm.doc.new_item) {
            frappe.call({
                method: "havano_hotel_management.api.get_item_price",
                args: {
                    item_id: frm.doc.new_item,
                    price_list: frm.doc.price_list  // pass selected price_list field
                },
                callback: function(r) {
                    if (r.message !== undefined) {
                        frm.set_value("price_list_rate", r.message);
                    }
                }
            });
        } else {
            frm.set_value("price_list_rate", 0);
        }
    },

    price_list(frm) {
        // if user changes price_list after selecting item, update rate
        if (frm.doc.new_item) {
            frappe.call({
                method: "havano_hotel_management.api.get_item_price",
                args: {
                    item_id: frm.doc.new_item,
                    price_list: frm.doc.price_list
                },
                callback: function(r) {
                    if (r.message !== undefined) {
                        frm.set_value("price_list_rate", r.message);
                    }
                }
            });
        }
    }
});

function toggle_new_item(frm) {
    if (frm.doc.override_item) {
        frm.set_df_property("new_item", "hidden", 0);
    } else {
        frm.set_df_property("new_item", "hidden", 1);
        frm.set_value("new_item", null);
        frm.set_value("price_list_rate", 0);
    }
}
